import json
import os

def get_default_error_profile():
    # Hardcoded default profile
    default_profile = [1, 0.06, 0.02, 0.02, 0.01, 0.005, 0.005, 0.005, 0.001, 0.001, 0.001, 0.0005]

    # Check if file exists
    if os.path.exists('default_error_profile.json'):
        with open('default_error_profile.json', 'r') as f:
            profile = json.load(f)
    else:
        profile = default_profile

    # Validate: must be list of length 12, all numeric in [0,1], non-increasing
    if not isinstance(profile, list) or len(profile) != 12:
        raise ValueError("Error profile must be a list of 12 elements")
    if any(not isinstance(v, (int, float)) or v < 0 or v > 1 for v in profile):
        raise ValueError("All error profile values must be numeric and in [0,1]")
    for i in range(1, len(profile)):
        if profile[i] > profile[i-1]:
            raise ValueError("Error profile must be non-increasing")

    # Return a copy to prevent mutation
    return list(profile)
